-- 08_map_data.sql
-- 매장 지도 및 선반(fixtures) 데이터
-- QGIS에서 내보낸 fix_store.sql, fix_shelves.sql의 WKB 데이터를 기존 스키마에 통합
-- 참고: WKB는 MULTIPOLYGON이므로 ST_GeometryN()으로 첫 번째 Polygon 추출

-- ============================================================
-- 1. 매장 경계 (store_maps)
-- ============================================================
INSERT INTO store_maps (store_map_id, version, boundary, units)
VALUES (
    '1',
    '1',
    ST_GeometryN(
        ST_GeomFromWKB(
            decode('', 'hex'),
            3857
        ),
        1
    ),
    'meters'
)
ON CONFLICT (store_map_id) DO UPDATE SET 
    boundary = EXCLUDED.boundary,
    version = EXCLUDED.version;

-- ============================================================
-- 2. 선반/진열대 (fixtures)
-- ============================================================

-- Shelf A - pc-fruits (과일)
INSERT INTO fixtures (fixture_id, parent_category_id, map_id, fixture_geom, label)
VALUES (
    'shelf-a', 'pc-fruits', '1',
    ST_GeometryN(ST_GeomFromWKB(decode('0106000020110F00000100000001030000000100000005000000E08AD545852300C0000BA52A3CADB83F205F037A3117D7BF009AAC1B8537DD3F907D42D8AA43E13F9CE8B7360E2407C0F87A0F1BEA72F2BF8453D8F894050AC0E08AD545852300C0000BA52A3CADB83F', 'hex'), 3857), 1),
    'Bay A - 과일'
)
ON CONFLICT (parent_category_id) DO UPDATE SET fixture_geom = EXCLUDED.fixture_geom, label = EXCLUDED.label;

